//$Id$
import { NestedParser } from '../../../view/nested/nested-parser';
import { mathMax } from '../../../core/zc-constants';
import { d3_scaleLinear } from '../../../core/d3-constants';
import { pick } from '../../../utils/zcutils';
import { closestToCircle } from '../../../utils/geometry/circle';
import { closestToPolygon } from '../../../utils/geometry/polygon';
import { getHoverOptions } from '../legend-event-helpers';
import { invertMousePoint } from './size-slider-data-finder';

function SizeNestedDataFinder(mouse, eventType, d, index) {
    let manager = this,
        { options } = manager,
        { ticks, config, scale, viewBound, polygonPoints } = options,
        { ranges, nested: nestedConfig } = config,
        { hAlign, vAlign, shape = 'circle' } = nestedConfig.marker,
        hoverOptions = getHoverOptions(config),
        triggerOffset = mathMax(pick(hoverOptions.triggerOffset, 5), 0.1);

    let data = ticks.length - 1 - index; // as bigger value rendered first

    if (ranges && ranges.length) {
        return data;
    } else {
        let d2 = ticks[data],
            d1 = pick(ticks[data - 1], scale.domain()[0]),
            _x = NestedParser.x(viewBound, scale, hAlign),
            _y = NestedParser.y(viewBound, scale, vAlign),
            //
            c1 = [_x(d1), _y(d1)],
            c2 = [_x(d2), _y(d2)],
            p = [c2[0] + mouse[0], c2[1] + mouse[1]],
            //
            closest1,
            closest2;

        if (shape === 'circle') {
            closest1 = closestToCircle([...c1, scale(d1) / 2], p);
            closest2 = closestToCircle([...c2, scale(d2) / 2], p);
        } else {
            let polygonPoints1 = polygonPoints[index + 1] || [],
                polygonPoints2 = polygonPoints[index];

            closest1 = closestToPolygon(polygonPoints1.map(_ => [_[0] + c1[0], _[1] + c1[1]]), p);
            closest2 = closestToPolygon(polygonPoints2.map(_ => [_[0] + c2[0], _[1] + c2[1]]), p);
        }

        let _scale = d3_scaleLinear()
                .domain([0, closest1 + closest2])
                .range([d1, d2]),
            point = _scale(closest1);

        return invertMousePoint(scale(point), scale, { triggerOffset, round: true });
    }
}

export { SizeNestedDataFinder };
